43	  it("7 runes have base premium 175 G (no block possible across 7)", () => {
44	    const result = runScenario({
45	      customer: { yearsWithMHPCO: 0 },
46	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] }],
47	    });
48	    expect(result).toEqual({ results: [{ premium: 180 }] });
