50	
51	  // --- "Alike" components clarification (❓ same type, not same family) ---
52	  it("2 runes + 1 moonstone have base premium 75 G (no block — different types)", () => {
53	    const result = runScenario({
54	      customer: { yearsWithMHPCO: 0 },
55	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }] }],
56	    });
57	    expect(result).toEqual({ results: [{ premium: 80 }] });
