61	      customer: { yearsWithMHPCO: 0 },
62	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" }] }],
63	    });
64	    expect(result).toEqual({ results: [{ premium: 125 }] });
65	  });
66	
67	  // --- Modifier thresholds ---
68	  it("customer with exactly 2 years receives loyalty discount", () => {
69	    const result = runScenario({
70	      customer: { yearsWithMHPCO: 2 },
71	      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 0 }] }],
