78	
79	  // --- Rounding rules ---
80	  it.todo("premium calculation yielding 197.5 G rounds UP to 198 G (MHPCO favor)");
81	  it.todo("payout calculation yielding 350.5 G rounds DOWN to 350 G (MHPCO favor)");
82	  it.todo("intermediate amounts are kept as fractions; only the final premium/payout is rounded");
