90	  // --- Integration example 1: Newcomer with cursed sword ---
91	  it.todo("newcomer (0 years, no previous contract) with cursed sword (steel, ench 3) → premium 165 G (100 base + 50 curse + 10 first-insurance = 160 + 5 fee)");
92	
93	  // --- Integration example 2: Long-standing customer's second contract ---
94	  it.todo("long-standing customer (3 years, 2nd quote) with cursed sword (steel, ench 7) → premium 160 G (100 base + 50 curse + 30 high-ench - 20 loyalty + 10 first-insurance - 15 follow-up = 155 + 5 fee)");
95	  it.todo("first-insurance surcharge applies to every item in every quote, regardless of customer history (❓ clarification)");
96	
97	  // --- Claim processing: standard reimbursement (no special clauses) ---
98	  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (full minus 100 deductible)");
99	  it.todo("damage to a rune (insurance value 250 G), damage 200 G → payout 100 G (full minus 100 deductible; no special clause)");
100	
101	  // --- Claim processing: deductible per damage event ---
102	  it.todo("dragon attack damages insured sword (500 G) and amulet (300 G) → payout 600 G (100 deductible per item)");
103	
104	  // --- Enchantment threshold vs. dragon material ---
105	  it.todo("dragon-material sword, enchantment 8, damage 1000 G → payout 400 G (high-enchantment clause: 50%, then deductible)");
106	  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% rule wins over dragon material, then deductible: 500 - 100)");
107	  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (only dragon-material clause: full, then deductible: 800 - 100)");
108	  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (only high-enchantment clause: 50%, then deductible: 500 - 100)");
109	
110	  // --- Multiple items of the same type (❓ two swords) ---
111	  it.todo("policy covers two swords → insurance sum 2000 G (= 2 x 1000)");
112	  it.todo("dragon attack damages both swords; each damages entry treated as separate damage with own deductible");
113	  it.todo("damages array contains more entries of a type than the policy covers → whole claim rejected (non-zero exit)");
114	
115	  // --- Edge cases ---
116	  it.todo("quote includes item with unknown type (e.g. broomstick) → non-zero exit, error on stderr, no results on stdout");
117	  it.todo("claim references damage entry for an item not part of the policy (e.g. amulet damaged when only sword insured) → non-zero exit, error on stderr");
118	  it.todo("claim references damage entry with unknown item type → non-zero exit, error on stderr");
119	  it.todo("claim contains a damage entry with amount -200 → non-zero exit, error on stderr");
120	
121	  // --- CLI integration (reads JSON from stdin, writes results to stdout) ---
122	  it.todo("CLI scenario with a quote step writes {results: [{premium: N}]} to stdout");
123	  it.todo("CLI scenario with quote followed by claim referencing policy by zero-based step index produces results in same order as steps");
124	});
