1	const PROCESSING_FEE = 5;
2	const BLOCK_OF_THREE_DISCOUNT = 15;
3	const BLOCK_SIZE = 3;
4	const FIRST_INSURANCE_RATE = 0.1;
5	const LOYALTY_DISCOUNT_RATE = 0.2;
6	const LOYALTY_YEARS_THRESHOLD = 2;
7	
8	const ITEM_BASE_PRICES: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	  moonstone: 25,
15	};
16	
17	const MAIN_ITEM_TYPES = new Set(["sword", "amulet", "staff", "potion"]);
18	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
19	
20	type Item = { type: string };
21	type Customer = { yearsWithMHPCO?: number };
22	type Scenario = {
23	  customer?: Customer;
24	  steps: { op: string; items: Item[] }[];
25	};
26	
27	function countItemsByType(items: Item[]): Map<string, number> {
28	  const counts = new Map<string, number>();
29	  for (const item of items) {
30	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
31	  }
32	  return counts;
33	}
34	
35	function basePremiumForComponentGroup(type: string, count: number): number {
36	  const unitPrice = ITEM_BASE_PRICES[type];
37	  const subtotal = count * unitPrice;
38	  const discount = count === BLOCK_SIZE ? BLOCK_OF_THREE_DISCOUNT : 0;
39	  return subtotal - discount;
40	}
41	
42	function computePolicyBase(items: Item[]): number {
43	  const itemCountsByType = countItemsByType(items);
44	  let basePremium = 0;
45	  for (const [type, count] of itemCountsByType.entries()) {
46	    if (COMPONENT_TYPES.has(type)) {
47	      basePremium += basePremiumForComponentGroup(type, count);
48	    } else {
49	      basePremium += count * ITEM_BASE_PRICES[type];
50	    }
51	  }
52	  return basePremium;
53	}
54	
55	function computeFirstInsuranceSurcharge(items: Item[]): number {
56	  let surcharge = 0;
57	  for (const item of items) {
58	    if (MAIN_ITEM_TYPES.has(item.type)) {
59	      surcharge += ITEM_BASE_PRICES[item.type] * FIRST_INSURANCE_RATE;
60	    }
61	  }
62	  return surcharge;
63	}
64	
65	function computeLoyaltyDiscount(policyBase: number, customer: Customer): number {
66	  const years = customer.yearsWithMHPCO ?? 0;
67	  if (years >= LOYALTY_YEARS_THRESHOLD) {
68	    return policyBase * LOYALTY_DISCOUNT_RATE;
69	  }
70	  return 0;
71	}
72	
73	export function runScenario(scenario: unknown): unknown {
74	  const s = scenario as Scenario;
75	  const customer = s.customer ?? { yearsWithMHPCO: 0 };
76	  const items = s.steps[0].items;
77	
78	  const policyBase = computePolicyBase(items);
79	  const firstInsurance = computeFirstInsuranceSurcharge(items);
80	  const loyaltyDiscount = computeLoyaltyDiscount(policyBase, customer);
81	
82	  const premium = policyBase + firstInsurance - loyaltyDiscount + PROCESSING_FEE;
83	  return { results: [{ premium }] };
84	}
